/**
 * Reverse lookup map from career level titles to {careerName, level} pairs.
 * Built from CAREER_SCHEMES at module load time.
 */
export const CAREER_LEVEL_TITLES: Record<string, { careerName: string; levelNumber: number }> = {};
for (const [careerName, careerData] of Object.entries(CAREER_SCHEMES)) {
  for (let i = 1; i <= 4; i++) {
    const levelData = careerData[`level${i}` as keyof CareerScheme] as { title: string } | undefined;
    if (levelData && levelData.title) {
      CAREER_LEVEL_TITLES[levelData.title] = { careerName, levelNumber: i };
    }
  }
}
